// App.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  ScrollView,
  Platform,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Linking from 'expo-linking';
import * as WebBrowser from 'expo-web-browser';
import * as Crypto from 'expo-crypto';

// ============================================================
// WARNING: Storing client_secret in a mobile app is a security
// risk. Mobile apps are considered "public clients" in OAuth 2.0
// and should use PKCE (Proof Key for Code Exchange) without a
// client_secret. The client_secret can be extracted from the
// app binary through reverse engineering.
//
// This implementation includes client_secret as requested but
// also implements PKCE for additional security. In production,
// prefer using PKCE-only flow without client_secret for mobile.
// ============================================================

// --- OAuth Configuration ---
const OAUTH_CONFIG = {
  clientId: 'your-client-id-here',
  // WARNING: client_secret should NOT be stored in mobile apps in production.
  // Mobile apps are public clients and can be reverse-engineered.
  // Use PKCE flow without client_secret for production mobile apps.
  clientSecret: 'your-client-secret-here',
  authorizationEndpoint: 'https://your-oauth-server.com/authorize',
  tokenEndpoint: 'https://your-oauth-server.com/token',
  revocationEndpoint: 'https://your-oauth-server.com/revoke',
  userInfoEndpoint: 'https://your-oauth-server.com/userinfo',
  redirectUri: Linking.createURL('oauth/callback'),
  scopes: ['openid', 'profile', 'email', 'offline_access'],
};

// --- Storage Keys ---
const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  ID_TOKEN: '@oauth_id_token',
  USER_INFO: '@oauth_user_info',
};

// --- PKCE Helper Functions ---
const generateRandomString = async (length = 64) => {
  const randomBytes = await Crypto.getRandomBytesAsync(length);
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  for (let i = 0; i < length; i++) {
    result += chars[randomBytes[i] % chars.length];
  }
  return result;
};

const generateCodeChallenge = async (codeVerifier) => {
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    codeVerifier,
    { encoding: Crypto.CryptoEncoding.BASE64 }
  );
  // Convert base64 to base64url
  return digest.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
};

// --- Token Storage Service ---
class TokenStorageService {
  static async saveTokens(tokenResponse) {
    const { access_token, refresh_token, expires_in, id_token } = tokenResponse;
    const expiryTime = Date.now() + (expires_in || 3600) * 1000;

    const pairs = [
      [STORAGE_KEYS.ACCESS_TOKEN, access_token],
      [STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()],
    ];

    if (refresh_token) {
      pairs.push([STORAGE_KEYS.REFRESH_TOKEN, refresh_token]);
    }
    if (id_token) {
      pairs.push([STORAGE_KEYS.ID_TOKEN, id_token]);
    }

    await AsyncStorage.multiSet(pairs);
  }

  static async getAccessToken() {
    return await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
  }

  static async getRefreshToken() {
    return await AsyncStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);
  }

  static async getTokenExpiry() {
    const expiry = await AsyncStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRY);
    return expiry ? parseInt(expiry, 10) : 0;
  }

  static async isTokenExpired() {
    const expiry = await this.getTokenExpiry();
    // Consider token expired 60 seconds before actual expiry
    return Date.now() >= expiry - 60000;
  }

  static async clearTokens() {
    await AsyncStorage.multiRemove(Object.values(STORAGE_KEYS));
  }

  static async saveUserInfo(userInfo) {
    await AsyncStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(userInfo));
  }

  static async getUserInfo() {
    const data = await AsyncStorage.getItem(STORAGE_KEYS.USER_INFO);
    return data ? JSON.parse(data) : null;
  }
}

// --- OAuth Authentication Service ---
class OAuthService {
  static codeVerifier = null;
  static state = null;
  static refreshPromise = null;

  static async startAuthorizationFlow() {
    // Generate PKCE code verifier and challenge
    this.codeVerifier = await generateRandomString(64);
    const codeChallenge = await generateCodeChallenge(this.codeVerifier);

    // Generate state parameter for CSRF protection
    this.state = await generateRandomString(32);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scopes.join(' '),
      state: this.state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
      // Request offline_access for refresh tokens
      access_type: 'offline',
      prompt: 'consent',
    });

    const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;

    const result = await WebBrowser.openAuthSessionAsync(
      authUrl,
      OAUTH_CONFIG.redirectUri
    );

    if (result.type === 'success' && result.url) {
      return this.handleRedirect(result.url);
    } else if (result.type === 'cancel' || result.type === 'dismiss') {
      throw new Error('Authentication was cancelled by the user.');
    } else {
      throw new Error('Authentication failed. Please try again.');
    }
  }

  static async handleRedirect(url) {
    const parsedUrl = Linking.parse(url);
    const { code, state, error, error_description } = parsedUrl.queryParams || {};

    if (error) {
      throw new Error(error_description || error || 'Authorization failed.');
    }

    if (!code) {
      throw new Error('No authorization code received.');
    }

    // Validate state parameter
    if (state !== this.state) {
      throw new Error('State mismatch. Possible CSRF attack detected.');
    }

    // Exchange authorization code for tokens
    return this.exchangeCodeForTokens(code);
  }

  static async exchangeCodeForTokens(code) {
    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      // WARNING: Including client_secret in mobile app as requested.
      // This is NOT recommended for production mobile applications.
      client_secret: OAUTH_CONFIG.clientSecret,
      code_verifier: this.codeVerifier,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Accept: 'application/json',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        errorData.error_description ||
          errorData.error ||
          `Token exchange failed with status ${response.status}`
      );
    }

    const tokenResponse = await response.json();
    await TokenStorageService.saveTokens(tokenResponse);

    // Clean up PKCE and state values
    this.codeVerifier = null;
    this.state = null;

    return tokenResponse;
  }

  static async refreshAccessToken() {
    // Prevent multiple simultaneous refresh requests
    if (this.refreshPromise) {
      return this.refreshPromise;
    }

    this.refreshPromise = this._performTokenRefresh();

    try {
      const result = await this.refreshPromise;
      return result;
    } finally {
      this.refreshPromise = null;
    }
  }

  static async _performTokenRefresh() {
    const refreshToken = await TokenStorageService.getRefreshToken();

    if (!refreshToken) {
      throw new Error('No refresh token available. Please login again.');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
      // WARNING: Including client_secret in mobile app as requested.
      client_secret: OAUTH_CONFIG.clientSecret,
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Accept: 'application/json',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));

      // If refresh token is invalid/expired, clear tokens
      if (response.status === 400 || response.status === 401) {
        await TokenStorageService.clearTokens();
        throw new Error('Session expired. Please login again.');
      }

      throw new Error(
        errorData.error_description ||
          errorData.error ||
          `Token refresh failed with status ${response.status}`
      );
    }

    const tokenResponse = await response.json();
    await TokenStorageService.saveTokens(tokenResponse);
    return tokenResponse;
  }

  static async getValidAccessToken() {
    const isExpired = await TokenStorageService.isTokenExpired();

    if (isExpired) {
      try {
        await this.refreshAccessToken();
      } catch (error) {
        throw error;
      }
    }

    return await TokenStorageService.getAccessToken();
  }

  static async fetchUserInfo() {
    const accessToken = await this.getValidAccessToken();

    if (!accessToken) {
      throw new Error('No access token available.');
    }

    const response = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        Accept: 'application/json',
      },
    });

    if (!response.ok) {
      if (response.status === 401) {
        // Token might be invalid, try refreshing once
        try {
          await this.refreshAccessToken();
          const newToken = await TokenStorageService.getAccessToken();
          const retryResponse = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
            headers: {
              Authorization: `Bearer ${newToken}`,
              Accept: 'application/json',
            },
          });
          if (!retryResponse.ok) {
            throw new Error('Failed to fetch user info after token refresh.');
          }
          const userInfo = await retryResponse.json();
          await TokenStorageService.saveUserInfo(userInfo);
          return userInfo;
        } catch (refreshError) {
          throw refreshError;
        }
      }
      throw new Error(`Failed to fetch user info: ${response.status}`);
    }

    const userInfo = await response.json();
    await TokenStorageService.saveUserInfo(userInfo);
    return userInfo;
  }

  static async revokeToken() {
    const accessToken = await TokenStorageService.getAccessToken();
    const refreshToken = await TokenStorageService.getRefreshToken();

    const revokePromises = [];

    if (refreshToken) {
      const body = new URLSearchParams({
        token: refreshToken,
        token_type_hint: 'refresh_token',
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
      });

      revokePromises.push(
        fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: body.toString(),
        }).catch(() => {})
      );
    }

    if (accessToken) {
      const body = new URLSearchParams({
        token: accessToken,
        token_type_hint: 'access_token',
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
      });

      revokePromises.push(
        fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: body.toString(),
        }).catch(() => {})
      );
    }

    await Promise.allSettled(revokePromises);
    await TokenStorageService.clearTokens();
  }

  // Authenticated fetch wrapper with automatic token refresh
  static async authenticatedFetch(url, options = {}) {
    let accessToken = await this.getValidAccessToken();

    if (!accessToken) {
      throw new Error('Not authenticated. Please login.');
    }

    const headers = {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
    };

    let response = await fetch(url, { ...options, headers });

    // If 401, try refreshing and retrying once
    if (response.status === 401) {
      try {
        await this.refreshAccessToken();
        accessToken = await TokenStorageService.getAccessToken();

        response = await fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            Authorization: `Bearer ${accessToken}`,
          },
        });
      } catch (refreshError) {
        throw new Error('Session expired. Please login again.');
      }
    }

    return response;
  }
}

// --- Auto Token Refresh Hook ---
const useAutoTokenRefresh = (isAuthenticated, onSessionExpired) => {
  const refreshTimerRef = useRef(null);

  const scheduleTokenRefresh = useCallback(async () => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    try {
      const expiry = await TokenStorageService.getTokenExpiry();
      const now = Date.now();
      // Refresh 2 minutes before expiry
      const refreshTime = expiry - now - 120000;

      if (refreshTime > 0) {
        refreshTimerRef.current = setTimeout(async () => {
          try {
            await OAuthService.refreshAccessToken();
            // Schedule next refresh
            scheduleTokenRefresh();
          } catch (error) {
            console.error('Auto token refresh failed:', error.message);
            if (onSessionExpired) {
              onSessionExpired();
            }
          }
        }, refreshTime);
      } else {
        // Token is already expired or about to expire, refresh now
        try {
          await OAuthService.refreshAccessToken();
          scheduleTokenRefresh();
        } catch (error) {
          console.error('Immediate token refresh failed:', error.message);
          if (onSessionExpired) {
            onSessionExpired();
          }
        }
      }
    } catch (error) {
      console.error('Error scheduling token refresh:', error.message);
    }
  }, [onSessionExpired]);

  useEffect(() => {
    if (isAuthenticated) {
      scheduleTokenRefresh();
    }

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [isAuthenticated, scheduleTokenRefresh]);

  return { scheduleTokenRefresh };
};

// --- Main App Component ---
const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [tokenInfo, setTokenInfo] = useState(null);
  const [error, setError] = useState(null);

  const handleSessionExpired = useCallback(() => {
    setIsAuthenticated(false);
    setUserInfo(null);
    setTokenInfo(null);
    Alert.alert(
      'Session Expired',
      'Your session has expired. Please login again.',
      [{ text: 'OK' }]
    );
  }, []);

  useAutoTokenRefresh(isAuthenticated, handleSessionExpired);

  // Check for existing authentication on app start
  useEffect(() => {
    checkExistingAuth();
  }, []);

  const checkExistingAuth = async () => {
    try {
      setIsLoading(true);
      const accessToken = await TokenStorageService.getAccessToken();
      const refreshToken = await TokenStorageService.getRefreshToken();

      if (accessToken) {
        const isExpired = await TokenStorageService.isTokenExpired();

        if (isExpired && refreshToken) {
          try {
            await OAuthService.refreshAccessToken();
          } catch (refreshError) {
            await TokenStorageService.clearTokens();
            setIsLoading(false);
            return;
          }
        } else if (isExpired && !refreshToken) {
          await TokenStorageService.clearTokens();
          setIsLoading(false);
          return;
        }

        setIsAuthenticated(true);

        // Try to load cached user info
        const cachedUserInfo = await TokenStorageService.getUserInfo();
        if (cachedUserInfo) {
          setUserInfo(cachedUserInfo);
        }

        await updateTokenInfo();
      }
    } catch (error) {
      console.error('Error checking existing auth:', error.message);
    } finally {
      setIsLoading(false);
    }
  };

  const updateTokenInfo = async () => {
    const accessToken = await TokenStorageService.getAccessToken();
    const refreshToken = await TokenStorageService.getRefreshToken();
    const expiry = await TokenStorageService.getTokenExpiry();

    setTokenInfo({
      accessToken: accessToken ? `${accessToken.substring(0, 20)}...` : 'None',
      refreshToken: refreshToken ? `${refreshToken.substring(0, 20)}...` : 'None',
      expiresAt: expiry ? new Date(expiry).toLocaleString() : 'Unknown',
      isExpired: Date.now() >= expiry,
    });
  };

  const handleLogin = async () => {
    try {
      setIsAuthenticating(true);
      setError(null);

      await OAuthService.startAuthorizationFlow();

      setIsAuthenticated(true);
      await updateTokenInfo();

      // Fetch user info
      try {
        const info = await OAuthService.fetchUserInfo();
        setUserInfo(info);
      } catch (userInfoError) {
        console.warn('Could not fetch user info:', userInfoError.message);
      }
    } catch (error) {
      setError(error.message);
      console.error('Login error:', error.message);
    } finally {
      setIsAuthenticating(false);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await OAuthService.revokeToken();
      setIsAuthenticated(false);
      setUserInfo(null);
      setTokenInfo(null);
      setError(null);
    } catch (error) {
      console.error('Logout error:', error.message);
      // Clear local state even if revocation fails
      await TokenStorageService.clearTokens();
      setIsAuthenticated(false);
      setUserInfo(null);
      setTokenInfo(null);
    } finally {
      setIsLoading(false);
    }
  };

  const handleRefreshToken = async () => {
    try {
      setError(null);
      await OAuthService.refreshAccessToken();
      await updateTokenInfo();
      Alert.alert('Success', 'Token refreshed successfully!');
    } catch (error) {
      setError(error.message);
      if (error.message.includes('Session expired') || error.message.includes('login again')) {
        handleSessionExpired();
      }
    }
  };

  const handleFetchUserInfo = async () => {
    try {
      setError(null);
      const info = await OAuthService.fetchUserInfo();
      setUserInfo(info);
    } catch (error) {
      setError(error.message);
    }
  };

  const handleTestApiCall = async () => {
    try {
      setError(null);
      const response = await OAuthService.authenticatedFetch(
        'https://your-api-server.com/api/protected-resource'
      );

      if (response.ok) {
        const data = await response.json();
        Alert.alert('API Response', JSON.stringify(data, null, 2));
      } else {
        throw new Error(`API call failed with status ${response.status}`);
      }
    } catch (error) {
      setError(error.message);
    }
  };

  if (isLoading) {
    return (
      <View style={styles.centerContainer}>
        <ActivityIndicator size="large" color="#4A90D9" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container} contentContainerStyle={styles.contentContainer}>
      <View style={styles.header}>
        <Text style={styles.title}>OAuth 2.0 Demo</Text>
        <Text style={styles.subtitle}>
          Authorization Code Flow with PKCE
        </Text>
        <View style={styles.securityWarning}>
          <Text style={styles.warningText}>
            ⚠️ Security Note: This app includes client_secret as requested.
            In production, mobile apps should use PKCE-only flow without
            client_secret, as mobile apps are public clients.
          </Text>
        </View>
      </View>

      {error && (
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>❌ {error}</Text>
        </View>
      )}

      {!isAuthenticated ? (
        <View style={styles.loginSection}>
          <Text style={styles.sectionTitle}>Welcome</Text>
          <Text style={styles.description}>
            Please sign in to access protected resources.
          </Text>
          <TouchableOpacity
            style={[styles.button, styles.loginButton]}
            onPress={handleLogin}
            disabled={isAuthenticating}
          >
            {isAuthenticating ? (
              <ActivityIndicator color="#FFFFFF" />
            ) : (
              <Text style={styles.buttonText}>Sign In with OAuth</Text>
            )}
          </TouchableOpacity>

          <View style={styles.configInfo}>
            <Text style={styles.configTitle}>Configuration:</Text>
            <Text style={styles.configText}>
              Client ID: {OAUTH_CONFIG.clientId.substring(0, 15)}...
            </Text>
            <Text style={styles.configText}>
              Redirect URI: {OAUTH_CONFIG.redirectUri}
            </Text>
            <Text style={styles.configText}>
              Scopes: {OAUTH_CONFIG.scopes.join(', ')}
            </Text>
          </View>
        </View>
      ) : (
        <View style={styles.authenticatedSection}>
          <View style={styles.statusBadge}>
            <Text style={styles.statusText}>✅ Authenticated</Text>
          </View>

          {userInfo && (
            <View style={styles.card}>
              <Text style={styles.cardTitle}>User Info</Text>
              <Text style={styles.infoText}>
                Name: {userInfo.name || userInfo.preferred_username || 'N/A'}
              </Text>
              <Text style={styles.infoText}>
                Email: {userInfo.email || 'N/A'}
              </Text>
              {userInfo.sub && (
                <Text style={styles.infoText}>Subject: {userInfo.sub}</Text>
              )}
              {userInfo.email_verified !== undefined && (
                <Text style={styles.infoText}>
                  Email Verified: {userInfo.email_verified ? 'Yes' : 'No'}
                </Text>
              )}
            </View>
          )}

          {tokenInfo && (
            <View style={styles.card}>
              <Text style={styles.cardTitle}>Token Info</Text>
              <Text style={styles.infoText}>
                Access Token: {tokenInfo.accessToken}
              </Text>
              <Text style={styles.infoText}>
                Refresh Token: {tokenInfo.refreshToken}
              </Text>
              <Text style={styles.infoText}>
                Expires At: {tokenInfo.expiresAt}
              </Text>
              <Text
                style={[
                  styles.infoText,
                  { color: tokenInfo.isExpired ? '#E74C3C' : '#27AE60' },
                ]}
              >
                Status: {tokenInfo.isExpired ? 'Expired' : 'Valid'}
              </Text>
            </View>
          )}

          <View style={styles.actionsContainer}>
            <TouchableOpacity
              style={[styles.button, styles.refreshButton]}
              onPress={handleRefreshToken}
            >
              <Text style={styles.buttonText}>🔄 Refresh Token</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.button, styles.infoButton]}
              onPress={handleFetchUserInfo}
            >
              <Text style={styles.buttonText}>👤 Fetch User Info</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.button, styles.apiButton]}
              onPress={handleTestApiCall}
            >
              <Text style={styles.buttonText}>🌐 Test API Call</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[styles.button, styles.logoutButton]}
              onPress={handleLogout}
            >
              <Text style={styles.buttonText}>🚪 Sign Out</Text>
            </TouchableOpacity>
          </View>
        </View>
      )}

      <View style={styles.footer}>
        <Text style={styles.footerText}>
          Platform: {Platform.OS} | OAuth 2.0 + PKCE
        </Text>
      </View>
    </ScrollView>
  );
};

